static inline gpointer
main_signal_wrapper_get_instance_private (MainSignalWrapper* self)
{
	return G_STRUCT_MEMBER_P (self, MainSignalWrapper_private_offset);
}

MainSignalWrapper*
main_signal_wrapper_construct (GType object_type,
                               GObject* o,
                               gulong signal_id)
{
	MainSignalWrapper* self = NULL;
	g_return_val_if_fail (o != NULL, NULL);
	self = (MainSignalWrapper*) g_type_create_instance (object_type);
	self->priv->obj = o;
	self->priv->sig_id = signal_id;
	return self;
}

